import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import {
  DxDataGridModule,
  DxSelectBoxModule,
  DxTextBoxModule,
  DxButtonModule,
  DxLoadIndicatorModule,
  DxPopupModule,
} from 'devextreme-angular';
import { ResultViewerService } from '../../core/services/result-viewer.service';
import { DiffResultDto, DiffFilter, NrtRunSummary } from '../../core/models/nrt.models';

@Component({
  selector: 'app-diff-results',
  standalone: true,
  imports: [
    CommonModule, RouterLink,
    DxDataGridModule, DxSelectBoxModule, DxTextBoxModule,
    DxButtonModule, DxLoadIndicatorModule, DxPopupModule,
  ],
  templateUrl: './diff-results.component.html',
  styleUrls: ['./diff-results.component.scss'],
})
export class DiffResultsComponent implements OnInit {
  loading      = true;
  runsLoading  = true;
  diffs: DiffResultDto[]   = [];
  runs:  (NrtRunSummary & { label: string })[] = [];
  totalCount   = 0;

  // Selected run in the combo (null = all runs)
  runId: number | null = null;

  filter: DiffFilter = { page: 1, pageSize: 50 };
  tradeIdInput = '';
  bookInput    = '';
  deskInput    = '';

  readonly diffTypeOptions = [
    { value: null,              label: 'All Types'       },
    { value: 'InBothButDiff',   label: 'In Both (diff)'  },
    { value: 'OnlyInReference', label: 'Only in Ref'     },
    { value: 'OnlyInTarget',    label: 'Only in Target'  },
  ];

  // Detail popup
  detailVisible  = false;
  selectedDiff: DiffResultDto | null = null;
  parsedDiffs: { field: string; ref: unknown; tgt: unknown }[] = [];

  constructor(
    private viewer: ResultViewerService,
    private route:  ActivatedRoute,
    private router: Router,
  ) {}

  ngOnInit(): void {
    // Load runs list for the combo, then apply any ?runId= query param
    this.viewer.getRuns(1, 200).subscribe({
      next: result => {
        this.runs = result.items.map(r => ({
          ...r,
          label: `#${r.runId} — ${r.scenarioName}  (${r.referenceVersion} → ${r.targetVersion})`,
        }));
        this.runsLoading = false;
      },
      error: () => { this.runsLoading = false; },
    });

    this.route.queryParams.subscribe(params => {
      const id   = params['runId'];
      this.runId = id ? +id : null;
      this.resetFilters();
      if (this.runId) {
        this.loadDiffs();
      } else {
        this.diffs      = [];
        this.totalCount = 0;
        this.loading    = false;
      }
    });
  }

  onRunChange(runId: number | null): void {
    this.router.navigate(['/diff-results'], {
      queryParams:  runId ? { runId } : {},
      replaceUrl:   true,
    });
  }

  loadDiffs(): void {
    this.loading = true;
    const req = this.runId
      ? this.viewer.getDiffsForRun(this.runId, this.filter)
      : this.viewer.getDiffs(this.filter);
    req.subscribe({
      next: result => {
        this.diffs      = result.items;
        this.totalCount = result.totalCount;
        this.loading    = false;
      },
      error: () => { this.loading = false; },
    });
  }

  applyFilters(): void {
    this.filter = {
      ...this.filter,
      page:    1,
      tradeId: this.tradeIdInput || undefined,
      book:    this.bookInput    || undefined,
      desk:    this.deskInput    || undefined,
    };
    this.loadDiffs();
  }

  clearFilters(): void {
    this.resetFilters();
    this.loadDiffs();
  }

  onDiffTypeChange(val: string | null): void {
    this.filter = { ...this.filter, diffType: val ?? undefined, page: 1 };
    this.loadDiffs();
  }

  openDetail(diff: DiffResultDto): void {
    this.selectedDiff  = diff;
    this.parsedDiffs   = this.parseDiffs(diff.diffs);
    this.detailVisible = true;
  }

  parseDiffs(raw: string | null): { field: string; ref: unknown; tgt: unknown }[] {
    if (!raw) return [];
    try {
      const obj = JSON.parse(raw) as Record<string, { Ref: unknown; Tgt: unknown }>;
      return Object.entries(obj).map(([field, v]) => ({ field, ref: v.Ref, tgt: v.Tgt }));
    } catch { return []; }
  }

  isNumeric(v: unknown): boolean { return typeof v === 'number'; }

  calcDelta(ref: unknown, tgt: unknown): number {
    return (tgt as number) - (ref as number);
  }

  private resetFilters(): void {
    this.tradeIdInput = '';
    this.bookInput    = '';
    this.deskInput    = '';
    this.filter       = { page: 1, pageSize: 50 };
  }
}
